const parts = [$.input.ticker, $.input.companyName];
const staticTerms = "fundamental analysis revenue earnings financial statements 2024 2025";
return { query: parts.filter(Boolean).join(" ") + " " + staticTerms };

const financials = $.steps.searchFinancials.response.results || [];
const valuation = $.steps.searchValuation.response.results || [];

let sourcesText = 'FINANCIAL DATA SOURCES:\n';
financials.forEach((r, i) => {
  sourcesText += (i + 1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1800) + '\n\n';
});

sourcesText += '\nVALUATION DATA SOURCES:\n';
valuation.forEach((r, i) => {
  sourcesText += (financials.length + i + 1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1500) + '\n\n';
});

return { sourcesText, totalSources: financials.length + valuation.length };

const d = $.steps.compileSources.output;
const ticker = $.input.ticker;
const company = $.input.companyName;

let prompt = 'You are a senior equity research analyst. Perform a comprehensive fundamental analysis of ' + company + ' (' + ticker + ').\n\n';
prompt += 'RESEARCH DATA (' + d.totalSources + ' sources):\n';
prompt += d.sourcesText + '\n';
prompt += 'ANALYSIS REQUIREMENTS:\n';
prompt += '- Revenue trends and growth rates\n';
prompt += '- Earnings per share (EPS) and growth\n';
prompt += '- Profit margins (gross, operating, net)\n';
prompt += '- Valuation metrics (P/E, P/S, EV/EBITDA)\n';
prompt += '- Balance sheet health (debt/equity, current ratio)\n';
prompt += '- Competitive advantages and moat\n';
prompt += '- Key risks and headwinds\n';
prompt += '- Overall investment thesis\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "ticker": "' + ticker + '",\n';
prompt += '  "company": "' + company + '",\n';
prompt += '  "analysisDate": "YYYY-MM-DD",\n';
prompt += '  "financials": {\n';
prompt += '    "revenue": "latest revenue figure",\n';
prompt += '    "revenueGrowth": "YoY growth %",\n';
prompt += '    "eps": "latest EPS",\n';
prompt += '    "grossMargin": "gross margin %",\n';
prompt += '    "operatingMargin": "operating margin %",\n';
prompt += '    "netMargin": "net margin %"\n';
prompt += '  },\n';
prompt += '  "valuation": {\n';
prompt += '    "peRatio": "P/E ratio",\n';
prompt += '    "psRatio": "P/S ratio",\n';
prompt += '    "evEbitda": "EV/EBITDA"\n';
prompt += '  },\n';
prompt += '  "rating": "strong-buy|buy|hold|sell|strong-sell",\n';
prompt += '  "strengths": ["strength 1", "strength 2"],\n';
prompt += '  "risks": ["risk 1", "risk 2"],\n';
prompt += '  "investmentThesis": "comprehensive thesis paragraph",\n';
prompt += '  "analystSummary": "brief executive summary"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { ticker: $.input.ticker, company: $.input.companyName, rating: 'hold', investmentThesis: raw, analystSummary: raw.slice(0, 500) }; }

const ai = $.steps.parseAI.output;
const today = ai.analysisDate || new Date().toISOString().slice(0, 10);

let report = 'FUNDAMENTAL STOCK ANALYSIS REPORT
';
report += '='.repeat(50) + '
';
report += ai.company + ' (' + ai.ticker + ')
';
report += 'Date: ' + today + '
';
report += 'Rating: ' + (ai.rating || 'N/A').toUpperCase() + '

';
report += 'EXECUTIVE SUMMARY
';
report += '-'.repeat(30) + '
';
report += (ai.analystSummary || 'N/A') + '

';
report += 'FINANCIAL METRICS
';
report += '-'.repeat(30) + '
';
const fin = ai.financials || {};
report += '  Revenue: ' + (fin.revenue || 'N/A') + '
';
report += '  Revenue Growth: ' + (fin.revenueGrowth || 'N/A') + '
';
report += '  EPS: ' + (fin.eps || 'N/A') + '
';
report += '  Gross Margin: ' + (fin.grossMargin || 'N/A') + '
';
report += '  Operating Margin: ' + (fin.operatingMargin || 'N/A') + '
';
report += '  Net Margin: ' + (fin.netMargin || 'N/A') + '

';
report += 'VALUATION
';
report += '-'.repeat(30) + '
';
const val = ai.valuation || {};
report += '  P/E Ratio: ' + (val.peRatio || 'N/A') + '
';
report += '  P/S Ratio: ' + (val.psRatio || 'N/A') + '
';
report += '  EV/EBITDA: ' + (val.evEbitda || 'N/A') + '

';
report += 'STRENGTHS
';
report += '-'.repeat(30) + '
';
(ai.strengths || []).forEach((s, i) => { report += '  ' + (i + 1) + '. ' + s + '
'; });
report += '
RISKS
';
report += '-'.repeat(30) + '
';
(ai.risks || []).forEach((r, i) => { report += '  ' + (i + 1) + '. ' + r + '
'; });
report += '
INVESTMENT THESIS
';
report += '-'.repeat(30) + '
';
report += (ai.investmentThesis || 'N/A') + '
';
report += '
---
Generated by One CLI | Exa + Claude AI
';

const fileName = 'stock-analysis-' + ai.ticker + '-' + today + '.txt';
return { report, fileName };
